class GamePage extends ConsumerStatefulWidget { const GamePage({super.key, required this.initial}); final Game initial; @override ConsumerState<GamePage> createState() => _GamePageState(); }
class _GamePageState extends ConsumerState<GamePage> with WidgetsBindingObserver {
