  Future<void> _refresh() async { try { final game = await ref.read(gameRepositoryProvider).get(_game.id); if (mounted) setState(() { _game = game; _error = null; _startClock(); }); } on ApiException catch (error) { if (mounted) setState(() => _error = error.message); } }
  Future<void> _choose(int choice) async { if (_sending || _game.remaining <= 0) return; setState(() { _sending = true; _error = null; }); try { final game = await ref.read(gameRepositoryProvider).choose(_game.id, choice); if (mounted) setState(() { _game = game; _startClock(); }); } on ApiException catch (error) { if (mounted) setState(() => _error = error.message); } finally { if (mounted) setState(() => _sending = false); } }
  Future<bool> _leave() async { if (_game.status != 'active') return true; final leave = await showDialog<bool>(context: context, builder: (context) => AlertDialog(title: const Text('تسيب المهمة؟'), content: const Text('لو سبتها مش هتظهر لك تاني.'), actions: [TextButton(onPressed: () => Navigator.pop(context, false), child: const Text('كمّل')), FilledButton(onPressed: () => Navigator.pop(context, true), child: const Text('سيبها'))])); if (leave == true) { await ref.read(gameRepositoryProvider).abandon(_game.id); return true; } return false; }
